              <select 
                value={currentUserId}
                onChange={handleRoleChange}
                className="w-full sm:w-auto bg-slate-100 text-[10px] font-black uppercase px-4 py-2.5 rounded-xl border-none outline-none focus:ring-2 focus:ring-blue-600 cursor-pointer shadow-sm"
              >
                {MOCK_USERS.map(u => (
                  <option key={u.id} value={u.id}>{u.name} — {t(`roles.${u.role}`).toUpperCase()}</option>
                ))}
              </select>
           </div>
           <div className="flex items-center space-x-4">
              <span className={`w-2 h-2 rounded-full ${currentUser.isOnline ? 'bg-green-500' : 'bg-slate-400'}`}></span>
              <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Entorno Sincronizado</span>
           </div>
        </div>

        <main className="flex-1 overflow-y-auto custom-scrollbar">
          <Routes>
            <Route path="super_admin/overview" element={<div className="p-12 space-y-12"><header><h1 className="text-3xl md:text-4xl font-black tracking-tighter">{t('dashboard.overview')}</h1></header><StatGrid stats={[{ label: t('dashboard.stats.total_users'), value: "3.2k" }, { label: "Servidores", value: "Online" }, { label: "Tráfico Hoy", value: "1.4k" }, { label: "Alertas", value: "0" }]} /><AdminUserManagement /></div>} />
            <Route path="super_admin/users" element={<AdminUserManagement />} />
            <Route path="super_admin/companies" element={<CompanyAudit />} />
            <Route path="super_admin/opportunities" element={<Opportunities />} />
            <Route path="company/overview" element={<div className="p-12 space-y-12"><header><h1 className="text-4xl font-black tracking-tighter">Panel de Proveedor</h1></header><StatGrid stats={[{label: "Postulaciones", value: "4"}, {label: "Contratos Activos", value: "1"}]} /></div>} />
            <Route path="company/opportunities" element={<Opportunities />} />
            <Route path="*/lex" element={<div className="p-12 h-full max-w-5xl"><LexAssistant /></div>} />
            <Route path="*/messages" element={<div className="p-12 h-full flex items-center justify-center"><ChatWindow currentUser={currentUser} recipient={MOCK_USERS[1]} /></div>} />
            <Route path="*" element={<Navigate to={`overview`} />} />
          </Routes>
        </main>
      </div>
    </div>
  );
};

export default Dashboard;

