              <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest mr-4 hidden sm:block">Identidad Actual:</span>
              <select 
                value={currentUserId}
                onChange={(e) => handleRoleChange(e.target.value)}
                className="w-full sm:w-auto bg-slate-100 dark:bg-slate-700 text-[10px] font-black uppercase px-4 py-2.5 rounded-xl border-none outline-none focus:ring-2 focus:ring-blue-600 cursor-pointer shadow-sm text-slate-900 dark:text-white"
              >
                {MOCK_USERS.map(u => (
                  <option key={u.id} value={u.id}>{u.name} — {t(`roles.${u.role}`).toUpperCase()}</option>
                ))}
              </select>
           </div>
           <div className="flex items-center space-x-4">
              <span className={`w-2 h-2 rounded-full ${currentUser.isOnline ? 'bg-green-500' : 'bg-slate-400'}`}></span>
              <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Soberanía de Datos</span>
