      { path: '/dashboard/petrolera/opportunities', label: 'dashboard.tenders', icon: '📜' },
      { path: '/dashboard/petrolera/lex', label: 'Soporte LEX IA', icon: '⚖️' },
    ],
    [UserRole.COMPANY]: [
      { path: '/dashboard/company/overview', label: 'dashboard.overview', icon: '🏭' },
      { path: '/dashboard/company/notifications', label: 'Notificaciones', icon: '🔔' },
      { path: '/dashboard/company/documents', label: 'Gestión Documental', icon: '📁' },
      { path: '/dashboard/company/applications', label: 'Mis Aplicaciones', icon: '📄' },
      { path: '/dashboard/company/opportunities', label: 'dashboard.tenders', icon: '🔍' },
      { path: '/dashboard/company/lex', label: 'Legal LEX IA', icon: '⚖️' },
    ],
    [UserRole.EMPRESA_LOCAL]: [
      { path: '/dashboard/empresa_local/overview', label: 'dashboard.overview', icon: '💡' },
      { path: '/dashboard/empresa_local/notifications', label: 'Notificaciones', icon: '🔔' },
      { path: '/dashboard/empresa_local/documents', label: 'Gestión Documental', icon: '📁' },
      { path: '/dashboard/empresa_local/applications', label: 'Mis Aplicaciones', icon: '📄' },
      { path: '/dashboard/empresa_local/opportunities', label: 'dashboard.tenders', icon: '🔍' },
      { path: '/dashboard/empresa_local/lex', label: 'Legal LEX IA', icon: '⚖️' },
    ],
    [UserRole.PERSONA]: [
      { path: '/dashboard/persona/overview', label: 'dashboard.overview', icon: '👷' },
      { path: '/dashboard/persona/notifications', label: 'Notificaciones', icon: '🔔' },
      { path: '/dashboard/persona/jobs', label: 'dashboard.job_offers', icon: '🔍' },
    ],
  };

  const currentMenu = (menuGroups as any)[currentUser.role] || menuGroups[UserRole.SUPER_ADMIN];

  return (
    <aside className={`fixed xl:static inset-y-0 left-0 z-[1000] w-80 bg-slate-950 flex flex-col shrink-0 border-r border-white/5 transition-transform duration-500 ease-[cubic-bezier(0.4,0,0.2,1)] ${
      isOpen ? 'translate-x-0' : '-translate-x-full xl:translate-x-0'
    }`}>
      <div className="absolute top-6 right-[-60px] xl:hidden">
        <button 
          onClick={onClose}
          className="bg-blue-600 text-white p-4 rounded-xl shadow-[0_10px_30px_rgba(37,99,235,0.4)] flex items-center justify-center hover:bg-blue-50 transition-colors"
        >
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" />
          </svg>
        </button>
      </div>

      <div className="p-10 border-b border-white/5">
        <Link to="/" className="flex flex-col">
          <span className="text-2xl font-black text-white tracking-tighter">GE-CONTENT</span>
          <span className="text-[9px] font-black text-blue-500 uppercase tracking-[0.3em] mt-2">Plataforma Institucional</span>
        </Link>
      </div>

      <nav className="p-6 flex-1 space-y-2 overflow-y-auto custom-scrollbar">
        {currentMenu.map((item: any) => {
          const active = location.pathname.includes(item.path);
          return (
            <Link
              key={item.path}
              to={item.path}
              onClick={() => { if(window.innerWidth < 1280) onClose(); }}
              className={`flex items-center space-x-4 px-6 py-4 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                active 
                  ? 'bg-blue-600 text-white shadow-[0_10px_20px_rgba(37,99,235,0.2)]' 
                  : 'text-slate-500 hover:text-white hover:bg-white/5'
              }`}
            >
              <span className="text-xl">{item.icon}</span>
              <span>{t(item.label)}</span>
            </Link>
          );
        })}
      </nav>

      <div className="p-10 border-t border-white/5">
        <Link to="/login" className="flex items-center space-x-4 text-slate-500 hover:text-red-400 font-black text-[10px] uppercase tracking-widest transition-colors">
           <span className="text-lg">🚪</span>
           <span>Cerrar Sesión</span>
        </Link>
      </div>
    </aside>
  );
};

