const Dashboard: React.FC = () => {
  const { t } = i18n;
  const navigate = useNavigate();
  const location = useLocation();
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  // Simulación de sesión
  const [currentUserId, setCurrentUserId] = useState(localStorage.getItem('user_id') || 'u-1'); 
  const currentUser = useMemo(() => MOCK_USERS.find(u => u.id === currentUserId) || MOCK_USERS[0], [currentUserId]);

  const handleRoleChange = (userId: string) => {
    const user = MOCK_USERS.find(u => u.id === userId);
    if (user) {
      setCurrentUserId(userId);
      localStorage.setItem('user_id', userId);
      setIsSidebarOpen(false);
      navigate(`/dashboard/${user.role}/overview`);
    }
  };

  const toggleSidebar = () => setIsSidebarOpen(!isSidebarOpen);

  return (
    <div className="flex h-screen bg-slate-50 dark:bg-background-dark overflow-hidden relative">
      <DashboardSidebar 
        forcedUser={currentUser} 
        isOpen={isSidebarOpen} 
        onClose={() => setIsSidebarOpen(false)} 
      />

      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-slate-950/60 backdrop-blur-sm z-[55] xl:hidden transition-opacity animate-in fade-in duration-300"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      <div className="flex-1 flex flex-col min-w-0">
        <DashboardHeader onToggleSidebar={toggleSidebar} />

        <div className="bg-white/90 dark:bg-slate-800 border-b border-slate-100 dark:border-slate-700 px-6 md:px-10 py-4 flex flex-col sm:flex-row items-center justify-between shrink-0 gap-4">
           <div className="flex items-center w-full sm:w-auto">
              <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest mr-4 hidden sm:block">Identidad Actual:</span>
              <select 
                value={currentUserId}
                onChange={(e) => handleRoleChange(e.target.value)}
                className="w-full sm:w-auto bg-slate-100 dark:bg-slate-700 text-[10px] font-black uppercase px-4 py-2.5 rounded-xl border-none outline-none focus:ring-2 focus:ring-blue-600 cursor-pointer shadow-sm text-slate-900 dark:text-white"
              >
                {MOCK_USERS.map(u => (
                  <option key={u.id} value={u.id}>{u.name} — {t(`roles.${u.role}`).toUpperCase()}</option>
                ))}
              </select>
           </div>
           <div className="flex items-center space-x-4">
              <span className={`w-2 h-2 rounded-full ${currentUser.isOnline ? 'bg-green-500' : 'bg-slate-400'}`}></span>
              <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Soberanía de Datos</span>
           </div>
        </div>

        <main className="flex-1 overflow-y-auto custom-scrollbar">
          <Routes>
            <Route path="super_admin/overview" element={<AdminDashboardOverview />} />
            <Route path="super_admin/users" element={<AdminUserManagement />} />
            <Route path="super_admin/companies" element={<CompanyAudit />} />
            <Route path="super_admin/opportunities" element={<Opportunities isDashboard />} />
            <Route path="super_admin/reports" element={<AuditReports />} />
            <Route path="super_admin/messages" element={<Messages />} />
            <Route path="super_admin/settings" element={<Settings />} />
            <Route path="super_admin/community" element={<CommunityManagement />} />

            <Route path="funcionario/overview" element={<AdminDashboardOverview />} />
            <Route path="funcionario/companies" element={<CompanyAudit />} />
            <Route path="funcionario/opportunities" element={<Opportunities isDashboard />} />
            <Route path="funcionario/reports" element={<AuditReports />} />
            <Route path="funcionario/messages" element={<Messages />} />
            <Route path="funcionario/settings" element={<Settings />} />
            <Route path="funcionario/community" element={<CommunityManagement />} />

