import React, { useState, useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { MOCK_APPLICATIONS } from '../services/mockService';
// Fixed: Imported ApplicationExt from types.ts instead of services/mockService
import { ApplicationExt } from '../types';

const ApplicationsTracking: React.FC = () => {
  const { t } = useTranslation();
  const [filter, setFilter] = useState<string>('all');
  const [searchQuery, setSearchQuery] = useState('');

  const stats = {
    total: MOCK_APPLICATIONS.length,
    review: MOCK_APPLICATIONS.filter(a => a.status === 'under_review').length,
    action: MOCK_APPLICATIONS.filter(a => a.actionRequired).length,
    awarded: MOCK_APPLICATIONS.filter(a => a.status === 'awarded').length,
  };

  const filteredApps = useMemo(() => {
    return MOCK_APPLICATIONS.filter(app => {
      const matchesFilter = 
        filter === 'all' || 
        (filter === 'review' && app.status === 'under_review') ||
        (filter === 'action' && app.actionRequired) ||
        (filter === 'awarded' && app.status === 'awarded');

      const matchesSearch = app.projectName.toLowerCase().includes(searchQuery.toLowerCase()) || app.ref.toLowerCase().includes(searchQuery.toLowerCase());

      return matchesFilter && matchesSearch;
    });
  }, [filter, searchQuery]);

  return (
    <div className="p-8 lg:p-12 space-y-12 animate-in fade-in duration-700">
      <header>
        <h1 className="text-4xl font-black text-slate-900 dark:text-white uppercase tracking-tighter">Seguimiento de Aplicaciones</h1>
        <p className="text-slate-500 dark:text-slate-400 mt-2 font-medium italic">Monitoree sus propuestas industriales en tiempo real.</p>
      </header>

      {/* Stats Grid */}
      <section className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        {[
          { label: "Total Aplicaciones", val: stats.total, icon: "folder_open", color: "text-blue-600", bg: "bg-blue-50" },
          { label: "En Revisión", val: stats.review, icon: "hourglass_top", color: "text-amber-600", bg: "bg-amber-50" },
          { label: "Acción Requerida", val: stats.action, icon: "error", color: "text-red-600", bg: "bg-red-50" },
          { label: "Adjudicadas", val: stats.awarded, icon: "verified", color: "text-green-600", bg: "bg-green-50" }
        ].map((s, i) => (
          <div key={i} className="bg-white dark:bg-slate-800 p-8 rounded-[2.5rem] border border-slate-100 dark:border-slate-700 shadow-sm flex items-center gap-6">
            <div className={`p-4 ${s.bg} dark:bg-opacity-10 rounded-2xl ${s.color}`}>
              <span className="material-symbols-outlined text-3xl">{s.icon}</span>
            </div>
            <div>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{s.label}</p>
              <p className="text-3xl font-black text-slate-900 dark:text-white tracking-tighter">{s.val}</p>
            </div>
          </div>
        ))}
      </section>

      {/* Filters & Search */}
      <section className="flex flex-col md:flex-row justify-between items-center gap-6 bg-white dark:bg-slate-800 p-6 rounded-[2.5rem] border border-slate-100 dark:border-slate-700 shadow-sm">
        <div className="flex overflow-x-auto gap-3 pb-2 md:pb-0 custom-scrollbar w-full md:w-auto">
          {[
            { id: 'all', label: 'Todas' },
            { id: 'review', label: 'En Revisión' },
            { id: 'action', label: 'Acción Requerida' },
            { id: 'awarded', label: 'Adjudicadas' }
          ].map(btn => (
            <button
              key={btn.id}
              onClick={() => setFilter(btn.id)}
              className={`px-8 py-3.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${
                filter === btn.id 
                  ? 'bg-slate-900 dark:bg-white text-white dark:text-slate-900 shadow-xl' 
                  : 'bg-slate-50 dark:bg-slate-700 text-slate-500 hover:bg-slate-100'
              }`}
            >
              {btn.label}
            </button>
          ))}
        </div>
        <div className="relative w-full md:w-96">
          <span className="absolute inset-y-0 left-5 flex items-center text-slate-400">
            <span className="material-symbols-outlined">search</span>
          </span>
          <input
            type="text"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full py-4 pl-14 pr-6 bg-slate-50 dark:bg-slate-700 border-none rounded-2xl focus:ring-2 focus:ring-primary text-xs font-black uppercase tracking-widest dark:text-white"
            placeholder="Buscar por ID o Proyecto..."
          />
        </div>
      </section>

      {/* Application List */}
      <section className="flex flex-col gap-10">
        {filteredApps.map((app) => (
          <article key={app.id} className="bg-white dark:bg-slate-800 rounded-[3.5rem] border border-slate-100 dark:border-slate-700 shadow-sm overflow-hidden group">
            <div className="p-10 lg:p-14">
              <div className="flex flex-col md:flex-row justify-between items-start gap-8 mb-14">
                <div className="flex gap-8">
                  <div className={`hidden sm:flex h-16 w-16 rounded-[1.5rem] items-center justify-center flex-shrink-0 shadow-inner ${
                    app.status === 'awarded' ? 'bg-green-50 text-green-600' : 
                    app.actionRequired ? 'bg-red-50 text-red-600' : 'bg-blue-50 text-primary'
                  }`}>
                    <span className="material-symbols-outlined text-3xl">
                      {app.status === 'awarded' ? 'celebration' : app.actionRequired ? 'gavel' : 'engineering'}
                    </span>
                  </div>
                  <div>
                    <div className="flex items-center gap-4 flex-wrap mb-3">
                      <h3 className="text-2xl font-black text-slate-900 dark:text-white uppercase tracking-tight group-hover:text-primary transition-colors">
                        {app.projectName}
                      </h3>
                      <span className={`px-4 py-1 rounded-full text-[9px] font-black uppercase tracking-widest ${
                        app.status === 'awarded' ? 'bg-green-100 text-green-700' :
                        app.actionRequired ? 'bg-red-100 text-red-700' : 'bg-amber-100 text-amber-700'
                      }`}>
                        {app.status.replace('_', ' ')}
                      </span>
                    </div>
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">
                      Ref: <span className="text-slate-600 dark:text-slate-300 font-bold">{app.ref}</span> • Enviado: {app.submittedAt}
                    </p>
                  </div>
                </div>
                <div className="flex gap-4 self-stretch md:self-center">
                  <button className={`px-8 py-4 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all shadow-xl ${
                    app.actionRequired 
                      ? 'bg-primary text-white hover:bg-blue-700 shadow-blue-500/20' 
                      : 'bg-slate-50 dark:bg-slate-700 text-primary hover:bg-blue-50'
                  }`}>
                    {app.actionRequired ? 'Subsanar Error' : app.status === 'awarded' ? 'Ver Contrato' : 'Ver Detalles'}
                  </button>
                </div>
              </div>

              {/* Progress Stepper */}
              <div className="relative mb-20 px-8">
                <div className="absolute top-4 left-10 right-10 h-1.5 bg-slate-100 dark:bg-slate-700 rounded-full"></div>
                <div 
                  className={`absolute top-4 left-10 h-1.5 rounded-full transition-all duration-1000 ${
                    app.actionRequired ? 'bg-red-500' : app.status === 'awarded' ? 'bg-green-500' : 'bg-primary'
                  }`} 
                  style={{ width: `${(app.step - 1) * 33.33}%` }}
                ></div>

                <div className="relative z-10 flex justify-between">
                  {['Enviada', 'Revisión', 'Pre-selección', 'Resultado'].map((stepName, i) => {
                    const stepNum = i + 1;
                    const isActive = app.step === stepNum;
                    const isPast = app.step > stepNum;
                    const isError = app.actionRequired && isActive;

                    return (
                      <div key={stepName} className="flex flex-col items-center">
                        <div className={`size-10 rounded-full flex items-center justify-center border-4 border-white dark:border-slate-800 shadow-lg transition-all ${
                          isError ? 'bg-red-500 text-white animate-pulse' :
                          isActive ? 'bg-primary text-white scale-125' :
                          isPast ? 'bg-primary text-white' : 'bg-slate-200 dark:bg-slate-600 text-slate-400'
                        }`}>
                          <span className="material-symbols-outlined text-lg">
                            {isError ? 'priority_high' : (isPast || (isActive && app.status === 'awarded')) ? 'check' : isActive ? 'hourglass_empty' : 'circle'}
                          </span>
                        </div>
                        <p className={`text-[9px] font-black uppercase tracking-widest mt-6 absolute w-24 text-center ${
                          isActive ? 'text-primary dark:text-blue-400' : 'text-slate-400'
                        }`}>
                          {stepName}
                        </p>
                      </div>
                    );
                  })}
                </div>
              </div>

              {/* Auditor Feedback Block */}
              {app.ministerComment && (
                <div className={`mt-20 p-8 rounded-[2rem] border flex items-start gap-6 ${
                  app.actionRequired 
                    ? 'bg-red-50 dark:bg-red-900/10 border-red-100 dark:border-red-900/30' 
                    : 'bg-blue-50 dark:bg-primary/10 border-blue-100 dark:border-primary/30'
                }`}>
                  <span className={`material-symbols-outlined text-2xl ${app.actionRequired ? 'text-red-500' : 'text-primary'}`}>
                    {app.actionRequired ? 'warning' : 'info'}
                  </span>
                  <div className="flex-1">
                    <p className="text-[10px] font-black text-slate-900 dark:text-white uppercase tracking-widest mb-2">Comentario de Auditoría Ministerial</p>
                    <p className={`text-sm font-medium italic ${app.actionRequired ? 'text-red-700 dark:text-red-300' : 'text-slate-600 dark:text-slate-300'}`}>
                      "{app.ministerComment}"
                    </p>
                    <div className="mt-4 flex gap-6">
                      <button className="text-[9px] font-black uppercase tracking-widest text-primary hover:underline flex items-center gap-2">
                        <span className="material-symbols-outlined text-sm">translate</span> Traducir Feedback
                      </button>
                      {app.actionRequired && (
                        <button className="text-[9px] font-black uppercase tracking-widest text-primary hover:underline flex items-center gap-2">
                          <span className="material-symbols-outlined text-sm">upload_file</span> Cargar Nuevo Documento
                        </button>
                      )}
                    </div>
                  </div>
                </div>
              )}
            </div>
          </article>
        ))}
      </section>

      {/* Footer Info */}
      <footer className="text-center py-10 opacity-40">
        <p className="text-[9px] font-black uppercase tracking-[0.5em] text-slate-400">Dirección General de Contenido Nacional • Guinea Ecuatorial</p>
      </footer>
    </div>
  );
};

