import React, { useState, useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { MOCK_OPPORTUNITIES, MOCK_APPLICATIONS } from '../services/mockService';
import { OpportunityExt } from '../types';

const OpportunityManagement: React.FC = () => {
  const { t, i18n } = useTranslation();
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState('Todas');
  const [activeSector, setActiveSector] = useState('');

  const getTranslatedText = (obj: any) => obj[i18n.language as any] || obj.es;

  // Estadísticas calculadas
  const stats = {
    total: MOCK_OPPORTUNITIES.length,
    active: MOCK_OPPORTUNITIES.filter(o => o.status === 'published').length,
    applicants: 850 // Simulado
  };

  const filteredOpps = useMemo(() => {
    return MOCK_OPPORTUNITIES.filter(opp => {
      const matchesSearch = getTranslatedText(opp.title).toLowerCase().includes(searchQuery.toLowerCase()) || 
                           (opp.ref || '').toLowerCase().includes(searchQuery.toLowerCase());
      const matchesStatus = statusFilter === 'Todas' || 
                           (statusFilter === 'Abiertas' && opp.status === 'published') ||
                           (statusFilter === 'Cerradas' && opp.status === 'closed') ||
                           (statusFilter === 'Borradores' && opp.status === 'under_review');
      const matchesSector = !activeSector || opp.category === activeSector;

      return matchesSearch && matchesStatus && matchesSector;
    });
  }, [searchQuery, statusFilter, activeSector, i18n.language]);

  const getStatusBadge = (status: string) => {
    switch (status) {
      case 'published':
        return (
          <span className="inline-flex items-center px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest bg-emerald-50 text-emerald-700 border border-emerald-100 dark:bg-emerald-900/20 dark:text-emerald-400">
            <span className="size-1.5 rounded-full bg-emerald-500 mr-2 animate-pulse"></span>
            Abierta
          </span>
        );
      case 'closed':
        return (
          <span className="inline-flex items-center px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest bg-red-50 text-red-700 border border-red-100 dark:bg-red-900/20 dark:text-red-400">
            <span className="size-1.5 rounded-full bg-red-500 mr-2"></span>
            Cerrada
          </span>
        );
      default:
        return (
          <span className="inline-flex items-center px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest bg-slate-100 text-slate-600 border border-slate-200 dark:bg-slate-700 dark:text-slate-300">
            <span className="size-1.5 rounded-full bg-slate-400 mr-2"></span>
            Borrador
          </span>
        );
    }
  };

  const getSectorIcon = (cat: string) => {
    switch (cat.toLowerCase()) {
      case 'mantenimiento': return 'handyman';
      case 'logística': return 'local_shipping';
      case 'ingeniería': return 'engineering';
      case 'catering': return 'restaurant';
      case 'seguridad': return 'security';
      default: return 'work';
    }
  };

  return (
    <div className="p-8 lg:p-12 space-y-12 animate-in fade-in duration-700">
      {/* Page Header */}
      <header className="flex flex-col md:flex-row md:items-start justify-between gap-6">
        <div className="space-y-2">
          <nav className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest text-slate-400">
            <span>Inicio</span>
            <span className="material-symbols-outlined text-base">chevron_right</span>
            <span className="text-primary">Oportunidades</span>
          </nav>
          <h1 className="text-4xl font-black text-slate-900 dark:text-white uppercase tracking-tighter">Gestión de Oportunidades</h1>
          <p className="text-slate-500 dark:text-slate-400 font-medium italic max-w-2xl">Supervise las licitaciones, gestione convocatorias activas y revise las aplicaciones de empresas.</p>
        </div>
        <button className="flex items-center gap-3 px-8 py-4 bg-primary text-white rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] hover:bg-blue-700 shadow-xl shadow-blue-500/20 transition-all active:scale-95">
          <span className="material-symbols-outlined text-xl">add_circle</span>
          Crear Oportunidad
        </button>
      </header>

      {/* Stats Section */}
      <section className="grid grid-cols-1 md:grid-cols-3 gap-8">
        {[
          { label: "Total Oportunidades", val: stats.total, icon: "folder_open", color: "text-blue-600", bg: "bg-blue-50", trend: "+12%" },
          { label: "Convocatorias Abiertas", val: stats.active, icon: "campaign", color: "text-orange-600", bg: "bg-orange-50", trend: "Activas hoy" },
          { label: "Total Aplicantes", val: stats.applicants, icon: "groups", color: "text-purple-600", bg: "bg-purple-50", trend: "+18%" }
        ].map((s, i) => (
          <div key={i} className="bg-white dark:bg-slate-800 p-8 rounded-[2.5rem] border border-slate-100 dark:border-slate-700 shadow-sm flex flex-col group relative overflow-hidden transition-all hover:shadow-md">
            <div className={`p-4 ${s.bg} dark:bg-opacity-10 rounded-2xl ${s.color} w-fit mb-6`}>
              <span className="material-symbols-outlined text-3xl">{s.icon}</span>
            </div>
            <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{s.label}</span>
            <div className="flex items-baseline gap-3">
              <span className="text-4xl font-black text-slate-900 dark:text-white tracking-tighter">{s.val}</span>
              <span className={`text-[9px] font-black uppercase tracking-widest ${s.color} bg-opacity-10 px-2 py-1 rounded-lg`}>{s.trend}</span>
            </div>
            <div className="absolute right-0 top-0 p-4 opacity-5 group-hover:opacity-10 transition-opacity">
              <span className="material-symbols-outlined text-7xl">{s.icon}</span>
            </div>
          </div>
        ))}
      </section>

      {/* Filters & Table */}
      <section className="bg-white dark:bg-slate-800 rounded-[3rem] border border-slate-100 dark:border-slate-700 shadow-sm overflow-hidden">
        {/* Toolbar */}
        <div className="p-6 md:p-8 border-b border-slate-50 dark:border-slate-700 flex flex-col lg:flex-row justify-between items-center gap-6">
          <div className="flex flex-1 gap-6 w-full lg:w-auto">
            <div className="relative flex-1 max-w-md group">
              <span className="absolute inset-y-0 left-5 flex items-center text-slate-400 group-focus-within:text-primary transition-colors">
                <span className="material-symbols-outlined">search</span>
              </span>
              <input 
                type="text" 
                placeholder="Buscar por título, ID o palabra clave..." 
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full pl-14 pr-6 py-4 bg-slate-50 dark:bg-slate-900 border-none rounded-2xl text-[10px] font-black uppercase tracking-widest focus:ring-2 focus:ring-primary dark:text-white shadow-inner"
              />
            </div>
            <div className="w-64 hidden sm:block">
              <select 
                value={activeSector}
                onChange={(e) => setActiveSector(e.target.value)}
                className="w-full bg-slate-50 dark:bg-slate-900 border-none rounded-2xl p-4 text-[10px] font-black uppercase tracking-widest focus:ring-2 focus:ring-primary dark:text-white cursor-pointer"
              >
                <option value="">Todos los Sectores</option>
                <option value="Mantenimiento">Mantenimiento</option>
                <option value="Logística">Logística</option>
                <option value="Ingeniería">Ingeniería</option>
              </select>
            </div>
          </div>

          <div className="flex gap-2 overflow-x-auto w-full lg:w-auto pb-2 lg:pb-0 custom-scrollbar">
            {['Todas', 'Abiertas', 'Cerradas', 'Borradores'].map(f => (
              <button
                key={f}
                onClick={() => setStatusFilter(f)}
                className={`px-6 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${
                  statusFilter === f 
                    ? 'bg-slate-900 dark:bg-white text-white dark:text-slate-900 shadow-xl' 
                    : 'bg-slate-100 dark:bg-slate-700 text-slate-500 hover:bg-slate-200'
                }`}
              >
                {f}
              </button>
            ))}
          </div>
        </div>

        {/* Table Content */}
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50/50 dark:bg-slate-900/50 border-b border-slate-100 dark:border-slate-700 text-slate-400 text-[10px] uppercase font-black tracking-[0.2em]">
                <th className="py-6 px-10">Oportunidad</th>
                <th className="py-6 px-10">Estado</th>
                <th className="py-6 px-10">Sector</th>
                <th className="py-6 px-10">Fecha Límite</th>
                <th className="py-6 px-10">Aplicantes</th>
                <th className="py-6 px-10 text-right">Acción</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 dark:divide-slate-700">
              {filteredOpps.map((opp) => (
                <tr key={opp.id} className="group hover:bg-slate-50/50 dark:hover:bg-slate-700/20 transition-all cursor-pointer">
                  <td className="py-8 px-10">
                    <div className="flex flex-col gap-2">
                      <div className="flex items-center gap-3">
                        <span className="text-[9px] font-mono text-slate-400 bg-slate-100 dark:bg-slate-900 px-2 py-1 rounded uppercase tracking-widest">
                          {opp.ref || opp.id.toUpperCase()}
                        </span>
                        {opp.tag === 'urgente' && <span className="size-2 rounded-full bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.5)]"></span>}
                      </div>
                      <p className="font-black text-slate-900 dark:text-white text-sm uppercase tracking-tight leading-tight">
                        {getTranslatedText(opp.title)}
                      </p>
                      <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Guinea Ecuatorial • {opp.location}</p>
                    </div>
                  </td>
                  <td className="py-8 px-10">
                    {getStatusBadge(opp.status)}
