import React, { useState, useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { MOCK_USERS } from '../services/mockService';
import { User, UserRole, UserStatus } from '../types';

const AdminUserManagementPage: React.FC = () => {
  const { t } = useTranslation();
  const [searchQuery, setSearchQuery] = useState('');
  const [roleFilter, setRoleFilter] = useState('Todos');
  const [deptFilter, setDeptFilter] = useState('Todos');

  const adminUsers = useMemo(() => {
    return MOCK_USERS.filter(u => 
      u.role === UserRole.SUPER_ADMIN || 
      u.role === UserRole.FUNCIONARIO || 
      u.role === UserRole.CUERPO_TECNICO ||
      u.role === UserRole.COMUNICACION
    );
  }, []);

  const filteredUsers = useMemo(() => {
    return adminUsers.filter(u => {
      const matchesSearch = u.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
                           u.email.toLowerCase().includes(searchQuery.toLowerCase()) ||
                           (u.position || '').toLowerCase().includes(searchQuery.toLowerCase());
      const matchesRole = roleFilter === 'Todos' || t(`roles.${u.role}`).includes(roleFilter);
      const matchesDept = deptFilter === 'Todos' || u.department === deptFilter;

      return matchesSearch && matchesRole && matchesDept;
    });
  }, [searchQuery, roleFilter, deptFilter, adminUsers, t]);

  const departments = ['Todos', 'Dirección General', 'Hidrocarburos', 'TI / Sistemas', 'Comunicaciones', 'Legal / Cumplimiento'];

  const getStatusBadge = (status?: UserStatus) => {
    switch (status) {
      case 'active':
        return (
          <span className="inline-flex items-center gap-1.5 rounded-full bg-emerald-50 px-3 py-1 text-[10px] font-black uppercase tracking-widest text-emerald-700 border border-emerald-100 dark:bg-emerald-900/30 dark:text-emerald-400 dark:border-emerald-900">
            <span className="size-1.5 rounded-full bg-emerald-500"></span>
            Activo
          </span>
        );
      case 'pending':
        return (
          <span className="inline-flex items-center gap-1.5 rounded-full bg-amber-50 px-3 py-1 text-[10px] font-black uppercase tracking-widest text-amber-700 border border-amber-100 dark:bg-amber-900/30 dark:text-amber-400 dark:border-amber-900">
            <span className="size-1.5 rounded-full bg-amber-500 animate-pulse"></span>
            Pendiente
          </span>
        );
      case 'inactive':
      case 'suspended':
        return (
          <span className="inline-flex items-center gap-1.5 rounded-full bg-slate-100 px-3 py-1 text-[10px] font-black uppercase tracking-widest text-slate-500 border border-slate-200 dark:bg-slate-800 dark:text-slate-400 dark:border-slate-700">
            <span className="size-1.5 rounded-full bg-slate-400"></span>
            Inactivo
          </span>
        );
      default: return null;
    }
  };

  const getRoleBadge = (role: UserRole) => {
    const roleColors: Record<string, string> = {
      [UserRole.SUPER_ADMIN]: 'bg-indigo-50 text-indigo-700 border-indigo-100 dark:bg-indigo-900/30 dark:text-indigo-300 dark:border-indigo-800',
      [UserRole.FUNCIONARIO]: 'bg-blue-50 text-blue-700 border-blue-100 dark:bg-blue-900/30 dark:text-blue-300 dark:border-blue-800',
      [UserRole.CUERPO_TECNICO]: 'bg-purple-50 text-purple-700 border-purple-100 dark:bg-purple-900/30 dark:text-purple-300 dark:border-purple-800',
      [UserRole.COMUNICACION]: 'bg-sky-50 text-sky-700 border-sky-100 dark:bg-sky-900/30 dark:text-sky-300 dark:border-sky-800',
    };

    return (
      <span className={`inline-flex items-center gap-1.5 rounded-md px-2.5 py-1 text-[10px] font-black uppercase tracking-widest border ${roleColors[role] || 'bg-slate-50 text-slate-600'}`}>
        {t(`roles.${role}`)}
      </span>
    );
  };

  return (
    <div className="p-8 lg:p-12 space-y-12 animate-in fade-in duration-700">
      {/* Breadcrumbs */}
      <nav className="flex items-center text-[10px] font-black uppercase tracking-widest text-slate-400">
        <a className="hover:text-primary transition-colors" href="#">Inicio</a>
        <span className="material-symbols-outlined mx-2 text-base">chevron_right</span>
        <a className="hover:text-primary transition-colors" href="#">Configuración</a>
        <span className="material-symbols-outlined mx-2 text-base">chevron_right</span>
        <span className="text-primary">Usuarios Admin</span>
      </nav>

      {/* Page Header */}
      <div className="flex flex-col gap-6 md:flex-row md:items-end md:justify-between">
        <div className="space-y-2">
          <h1 className="text-4xl font-black text-slate-900 dark:text-white uppercase tracking-tighter">Gestión de Usuarios Admin</h1>
          <p className="text-slate-500 dark:text-slate-400 font-medium italic max-w-2xl">
            Administra los accesos y permisos del personal del Ministerio. Asigna roles de supervisión para el contenido nacional.
          </p>
        </div>
        <button className="flex items-center gap-3 px-8 py-4 bg-primary text-white rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] hover:bg-blue-700 shadow-xl shadow-blue-500/20 transition-all active:scale-95">
          <span className="material-symbols-outlined text-xl">person_add</span>
          Nuevo Usuario
        </button>
      </div>

      {/* Content Card */}
      <div className="flex flex-col rounded-[3rem] border border-slate-100 bg-white shadow-sm dark:border-slate-800 dark:bg-slate-800 overflow-hidden">

        {/* Toolbar */}
        <div className="flex flex-col gap-6 border-b border-slate-50 p-8 dark:border-slate-700 lg:flex-row lg:items-center lg:justify-between">
          {/* Search */}
          <div className="relative w-full max-w-md group">
            <div className="pointer-events-none absolute inset-y-0 left-5 flex items-center text-slate-400 group-focus-within:text-primary transition-colors">
              <span className="material-symbols-outlined">search</span>
            </div>
            <input 
              type="text" 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="block w-full rounded-2xl border-none bg-slate-50 py-4 pl-14 pr-6 text-sm font-bold placeholder:text-slate-400 focus:ring-2 focus:ring-primary dark:bg-slate-900 dark:text-white shadow-inner uppercase tracking-tight" 
              placeholder="Buscar por nombre, email o cargo..." 
            />
          </div>

          {/* Chips / Filters */}
          <div className="flex flex-wrap items-center gap-4">
            <span className="text-[9px] font-black uppercase tracking-[0.2em] text-slate-400">Filtrar por:</span>

            <div className="relative group">
               <select 
                value={deptFilter}
                onChange={(e) => setDeptFilter(e.target.value)}
                className="appearance-none inline-flex items-center gap-3 rounded-xl border border-slate-100 bg-white px-6 py-3 text-[10px] font-black uppercase tracking-widest text-slate-700 hover:bg-slate-50 dark:border-slate-700 dark:bg-slate-800 dark:text-slate-300 transition-all cursor-pointer pr-12 focus:ring-2 focus:ring-primary outline-none"
               >
                 {departments.map(d => <option key={d} value={d}>Dept: {d}</option>)}
               </select>
               <span className="material-symbols-outlined absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none">expand_more</span>
            </div>

            <button className="inline-flex items-center gap-2 rounded-xl border-2 border-dashed border-slate-200 bg-transparent px-6 py-3 text-[10px] font-black uppercase tracking-widest text-slate-400 hover:border-primary hover:text-primary transition-all">
              <span className="material-symbols-outlined text-lg">filter_list</span>
              Más filtros
            </button>
          </div>
        </div>

        {/* Table */}
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50/50 text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 dark:bg-slate-900/50">
              <tr>
                <th className="px-10 py-6" scope="col">Funcionario</th>
                <th className="px-10 py-6" scope="col">Rol / Permisos</th>
                <th className="px-10 py-6" scope="col">Departamento</th>
                <th className="px-10 py-6" scope="col">Estado</th>
                <th className="px-10 py-6 text-right" scope="col">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50 dark:divide-slate-700">
              {filteredUsers.length > 0 ? filteredUsers.map((user) => (
                <tr key={user.id} className="group hover:bg-slate-50/50 dark:hover:bg-slate-700/20 transition-all">
                  <td className="px-10 py-8">
                    <div className="flex items-center gap-5">
                      <div className="relative">
                         <div className="size-12 rounded-2xl bg-slate-100 border-2 border-white dark:border-slate-700 shadow-sm overflow-hidden flex items-center justify-center font-black text-slate-400 text-lg">
                           {user.avatar ? <img src={user.avatar} className="w-full h-full object-cover" /> : user.name.charAt(0)}
                         </div>
                         {user.isOnline && <div className="absolute -bottom-1 -right-1 size-4 rounded-full border-4 border-white bg-green-500 dark:border-slate-800 shadow-sm"></div>}
                      </div>
                      <div className="flex flex-col">
                        <span className="text-sm font-black text-slate-900 dark:text-white uppercase tracking-tight leading-tight">{user.name}</span>
                        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1">{user.email}</span>
                      </div>
                    </div>
                  </td>
                  <td className="px-10 py-8">
                    <div className="flex flex-col gap-2">
                       {getRoleBadge(user.role)}
                       <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">{user.permissions.length === 1 && user.permissions[0] === '*' ? 'Acceso Total' : `${user.permissions.length} Permisos Específicos`}</p>
                    </div>
                  </td>
                  <td className="px-10 py-8">
                    <span className="text-xs font-black text-slate-600 dark:text-slate-300 uppercase tracking-tight">
                      {user.department || 'Sin Asignar'}
                    </span>
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1">{user.position || '-'}</p>
                  </td>
                  <td className="px-10 py-8">
                    {getStatusBadge(user.status)}
                  </td>
                  <td className="px-10 py-8 text-right">
                    <div className="flex items-center justify-end gap-2 opacity-20 group-hover:opacity-100 transition-opacity">
                      <button className="p-3 text-slate-400 hover:text-primary hover:bg-blue-50 dark:hover:bg-blue-900/20 rounded-xl transition-all" title="Editar Permisos">
                        <span className="material-symbols-outlined">edit</span>
                      </button>
                      <button className="p-3 text-slate-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-xl transition-all" title="Opciones">
                        <span className="material-symbols-outlined">more_vert</span>
                      </button>
                    </div>
                  </td>
                </tr>
              )) : (
                <tr>
                  <td colSpan={5} className="px-10 py-32 text-center">
                    <div className="flex flex-col items-center opacity-30 grayscale">
                       <span className="material-symbols-outlined text-8xl mb-4">person_search</span>
                       <p className="text-sm font-black uppercase tracking-[0.4em]">No se encontraron funcionarios</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>

        {/* Pagination */}
        <div className="flex items-center justify-between border-t border-slate-50 bg-slate-50/30 px-10 py-8 dark:border-slate-700 dark:bg-slate-900/20">
          <div className="text-[10px] font-black uppercase tracking-widest text-slate-400">
            Mostrando <span className="text-slate-900 dark:text-white mx-1">{filteredUsers.length}</span> de <span className="text-slate-900 dark:text-white mx-1">{adminUsers.length}</span> funcionarios
          </div>
          <div className="flex items-center gap-4">
            <button disabled className="px-8 py-3 bg-white border border-slate-200 text-slate-300 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all">Anterior</button>
            <div className="flex gap-2">
               <button className="size-10 bg-primary text-white font-black text-xs rounded-xl shadow-lg shadow-primary/20">1</button>
               <button className="size-10 bg-white border border-slate-100 text-slate-400 font-black text-xs rounded-xl hover:bg-slate-50 transition-all">2</button>
            </div>
            <button className="px-8 py-3 bg-white border border-slate-200 text-slate-700 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-slate-50 transition-all shadow-sm">Siguiente</button>
          </div>
        </div>
      </div>

      {/* Info Footer */}
      <footer className="text-center py-10 opacity-30">
        <p className="text-[9px] font-black uppercase tracking-[0.5em] text-slate-400">Sistema de Control de Identidad y Accesos • MMH Guinea Ecuatorial</p>
      </footer>
    </div>
  );
};

